-- Clean re-import of all Cyrene MobAreas from original SVG polygon data.
-- Deletes all existing Cyrene MobAreas and re-inserts from Cyrene3.svg.
-- Sets altitude to 100 for all areas.
-- Fixes Pleak (->Puny) and Imperium Officer (->Officer) single-maturity names.
-- Generated from Cyrene3.json (converted from Cyrene3.svg with transform corrections).

BEGIN;

-- Step 1: Collect IDs of Cyrene MobArea locations, then delete in order
CREATE TEMP TABLE _cyrene_delete_ids AS
SELECT l."Id"
FROM ONLY "Locations" l
JOIN ONLY "Areas" a ON a."LocationId" = l."Id"
WHERE l."PlanetId" = 7 AND a."Type" = 'MobArea';

DELETE FROM ONLY "MobSpawnMaturities" msm
WHERE msm."LocationId" IN (SELECT "Id" FROM _cyrene_delete_ids);

DELETE FROM ONLY "MobSpawns" ms
WHERE ms."LocationId" IN (SELECT "Id" FROM _cyrene_delete_ids);

DELETE FROM ONLY "Areas" a
WHERE a."LocationId" IN (SELECT "Id" FROM _cyrene_delete_ids);

DELETE FROM ONLY "Locations" l
WHERE l."Id" IN (SELECT "Id" FROM _cyrene_delete_ids);

DROP TABLE _cyrene_delete_ids;

-- Step 2: Insert all areas via temp table
CREATE TEMP TABLE _cyrene_import (
  tech_id TEXT PRIMARY KEY,
  name TEXT NOT NULL,
  shape TEXT NOT NULL,
  data JSONB NOT NULL
);


-- Step 3: Insert Locations with altitude 100
SELECT ci.name, 'Area', 7, ci.tech_id, 100
FROM _cyrene_import ci;

-- Step 4: Insert Areas (triggers update_coordinates_trigger for Longitude/Latitude)
SELECT l."Id", 'MobArea', ci.shape::"Shape", ci.data
FROM _cyrene_import ci
JOIN ONLY "Locations" l ON l."TechnicalId" = ci.tech_id AND l."PlanetId" = 7;

-- Step 5: Insert MobSpawnMaturities by parsing area names
-- Area names encode mob+maturity: "Mob - Mat1/Mat2", comma-separated for multi-mob areas.
-- Names without " - " use 'Default' maturity. If mob has only one maturity, 'Default' maps to it.
SELECT mm."Id" AS "MaturityId", l."Id" AS "LocationId", 0 AS "IsRare"
FROM ONLY "Locations" l
JOIN ONLY "Areas" a ON a."LocationId" = l."Id"
CROSS JOIN LATERAL unnest(string_to_array(l."Name", ',')) AS raw_segment
CROSS JOIN LATERAL (SELECT trim(raw_segment) AS segment) AS seg
CROSS JOIN LATERAL (
  SELECT
    CASE WHEN seg.segment LIKE '% - %' THEN trim(split_part(seg.segment, ' - ', 1))
         ELSE seg.segment END AS mob_name,
    CASE WHEN seg.segment LIKE '% - %' THEN split_part(seg.segment, ' - ', 2)
         ELSE 'Default' END AS maturity_part
) AS parsed
CROSS JOIN LATERAL unnest(string_to_array(parsed.maturity_part, '/')) AS maturity_name
JOIN ONLY "Mobs" m ON m."Name" = parsed.mob_name
JOIN ONLY "MobMaturities" mm ON mm."MobId" = m."Id"
  AND (
    mm."Name" = trim(maturity_name)
    OR (
      trim(maturity_name) = 'Default'
      AND NOT EXISTS (
        SELECT 1 FROM ONLY "MobMaturities" mm2
        WHERE mm2."MobId" = m."Id" AND mm2."Id" != mm."Id"
      )
    )
  )
WHERE l."PlanetId" = 7 AND a."Type" = 'MobArea'
ON CONFLICT ("MaturityId", "LocationId") DO NOTHING;

DROP TABLE _cyrene_import;

COMMIT;